// SINGLE source of truth. Add Cian here (create their ping sensor too).
const PEOPLE=[
 {name:'Colm',   person:'person.colm_finn',   ping:'binary_sensor.colm_phone_home',   notify:'notify.mobile_app_np3'},
 {name:'Olivia', person:'person.olivia_finn', ping:'binary_sensor.olivia_phone_home', notify:'notify.mobile_app_pixel_6a'},
 {name:'Daire',  person:'person.daire_finn',  ping:'binary_sensor.daire_phone_home',  notify:'notify.mobile_app_pixel_9a', onlyWhenHome:true}
 // ,{name:'Cian',  person:'person.cian_finn',  ping:'binary_sensor.cian_phone_home',  notify:'notify.mobile_app_pixel_7a'}
];
flow.set('people',PEOPLE);
global.set('people',PEOPLE);   // shared with the Alarm NFC Tags flow
return null;

// Alarm notification engine (state-derived) -> all people
const PEOPLE=flow.get('people')||[{notify:'notify.mobile_app_np3'},{notify:'notify.mobile_app_pixel_6a'}];
const ents=Array.isArray(msg.entities)?msg.entities:[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e&&e.state;};
const homeP=p=>S(p.person)==='home'||S(p.ping)==='on';
const FN=id=>{const e=ents.find(x=>x.entity_id===id);return (e&&e.attributes&&e.attributes.friendly_name)||id.split('.').pop().replace(/_contact$/,'').replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase());};
const PERSONS=['cian','colm','aoife','olivia','daire'];
const spoken=id=>{const nm=FN(id).trim();const w=nm.split(/\s+/);return (PERSONS.includes(w[0].toLowerCase())&&w.length>1)?(w[0]+"'s "+w.slice(1).join(' ').toLowerCase()):('the '+nm.toLowerCase());};
const ev=msg.payload||{};
const ns=ev.new_state||{}, os=ev.old_state||{};
const nw=ns.state, old=os.state, eid=ev.entity_id||'';
const area=eid.endsWith('.shed')?'Shed':'House';
if(eid==='alarm_control_panel.house'&&nw){flow.set('alarm_house',nw);global.set('alarm_house',nw);}
if(eid==='alarm_control_panel.shed'&&nw){global.set('alarm_shed',nw);}
const ARMED=['armed_away','armed_home','armed_night','armed_vacation','armed_custom_bypass'];
const opens=(ns.attributes&&ns.attributes.open_sensors)||null;
function ol(){ if(!opens) return ''; try{return ' Open: '+Object.keys(opens).map(id=>FN(id)).join(', ')+'.';}catch(e){return '';} }
let title=null,message=null,tag=null;
if(ARMED.includes(nw)&&!ARMED.includes(old)){title='🔒 '+area+' alarm armed';message='The '+area+' alarm is now armed.';tag='armed';}
else if(nw==='triggered'){title='🚨 '+area+' alarm TRIGGERED';message='The '+area+' alarm has been triggered!'+ol();tag='trig';}
else if(old==='triggered'&&nw!=='triggered'){title='✅ '+area+' alarm clear';message='The '+area+' alarm is no longer triggered.';tag='untrig';}
else if(nw==='disarmed'&&opens&&Object.keys(opens).length&&(old==='disarmed'||old==='arming')){title='⚠️ '+area+' failed to arm';message='The '+area+' alarm failed to arm.'+ol();tag='failed';}
else if(nw==='disarmed'&&(ARMED.includes(old)||old==='triggered'||old==='pending'||old==='arming')){title='🔓 '+area+' alarm disarmed';message='The '+area+' alarm has been disarmed.';tag='disarm';}
else { return null; }
const key=tag+'|'+message, last=context.get('last_'+eid);
if(last===key) return null;
context.set('last_'+eid,key);
node.warn('[alarm-notify] '+area+' '+tag+' -> '+PEOPLE.filter(p=>p.notify&&(!p.onlyWhenHome||homeP(p))).length+' people');
const ICON={armed:'mdi:shield-lock',trig:'mdi:alarm-light',untrig:'mdi:shield-check',disarm:'mdi:shield-off',failed:'mdi:shield-alert'};
const ico=ICON[tag]||'mdi:shield-home';
const out=PEOPLE.filter(p=>p.notify&&(!p.onlyWhenHome||homeP(p))).map(p=>({payload:{action:p.notify,data:{title:title,message:message,data:{notification_icon:ico}}}}));
const _aw=flow.get('awaitWelcome');const _welcomePending=!!(_aw&&(Date.now()-_aw.since)<8*60*1000);
let sm=null;
if(tag==='armed') sm=(nw==='armed_night')?null:(area+' alarm armed.');
else if(tag==='disarm') sm=(old==='armed_night')?null:((eid==='alarm_control_panel.house'&&_welcomePending)?null:(area+' alarm disarmed.'));
else if(tag==='trig') sm='Warning! The '+area+' alarm has been triggered.';
else if(tag==='untrig') sm='The '+area+' alarm is no longer triggered.';
else if(tag==='failed'){const ks=opens?Object.keys(opens):[];const isHouse=(eid==='alarm_control_panel.house');if(isHouse&&flow.get('failSpoken')){sm=null;}else{if(isHouse)flow.set('failSpoken',true);sm=ks.length===1?('Alarm failed to arm because '+spoken(ks[0])+' is open.'):'Alarm failed to arm. Multiple windows and or doors are open. Check Home Assistant.';}}
return [out, sm?{payload:{message:sm}}:null];

// Layer 3: low-battery alerts (alarm presence) -> Colm+Olivia
// Day (07-22): immediate low (<15%) + immediate recovery (>=15% AND charging).
// Night (22-07): silent, record events for the 07:00 catch-up summary.
const d=msg.data||{};
const eid=d.entity_id||msg.topic;
const nv=parseFloat(msg.payload);
const ov=parseFloat(d.old_state&&d.old_state.state);
if(isNaN(nv)) return null;
const ents=msg.entities||[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e?e.state:undefined;};
const NAME={'sensor.np3_battery_level':"Colm's",'sensor.pixel_6a_battery_level':"Olivia's"};
const STATE={'sensor.np3_battery_level':'sensor.np3_battery_state','sensor.pixel_6a_battery_level':'sensor.pixel_6a_battery_state'};
const who=NAME[eid];
if(!who) return null;
const charging=S(STATE[eid])==='charging';
const h=new Date().getHours();
const night=(h>=22||h<7);
const hhmm=()=>{const t=new Date();return ('0'+t.getHours()).slice(-2)+':'+('0'+t.getMinutes()).slice(-2);};
const ALERTS=['notify.mobile_app_np3','notify.mobile_app_pixel_6a'];
const push=(title,message)=>[ALERTS.map(a=>({payload:{action:a,data:{title:title,message:message,data:{notification_icon:'mdi:battery-alert'}}}}))];
// down-crossing below 15%
if(nv<15 && !(ov<15)){
  if(night){
    const rec=flow.get('battNight')||{};
    rec[eid]={who:who,lowPct:nv,lowAt:hhmm(),recovered:false};
    flow.set('battNight',rec);
    node.warn('[low-batt] night low '+eid+' '+nv+'% recorded');
    return null;
  }
  node.warn('[low-batt] '+eid+' '+nv+'%');
  return push('Phone battery low',who+' phone is at '+nv+'% - charge it so the alarm presence keeps working.');
}
// up-crossing above 15% AND charging -> recovery
if(nv>=15 && ov<15 && charging){
  if(night){
    const rec=flow.get('battNight')||{};
    const e=rec[eid]||{who:who,recovered:false};
    e.recovered=true; e.recPct=nv; e.recAt=hhmm();
    rec[eid]=e; flow.set('battNight',rec);
    node.warn('[low-batt] night recovery '+eid+' '+nv+'% recorded');
    return null;
  }
  node.warn('[low-batt] recovery '+eid+' '+nv+'%');
  return push('Phone battery recovering',who+' phone is back above 15% ('+nv+'%) and charging - alarm presence is covered again.');
}
return null;

// 07:00 overnight battery catch-up summary -> Colm+Olivia (only if events occurred)
const rec=flow.get('battNight')||{};
const eids=Object.keys(rec);
if(eids.length===0) return null;
const ents=msg.entities||[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e?e.state:undefined;};
const STATE={'sensor.np3_battery_level':'sensor.np3_battery_state','sensor.pixel_6a_battery_level':'sensor.pixel_6a_battery_state'};
const lines=eids.map(eid=>{
  const e=rec[eid];
  const nowPct=S(eid);
  const nowChg=S(STATE[eid])==='charging';
  let line='\u2022 '+e.who+' phone';
  if(e.lowAt) line+=' dropped to '+e.lowPct+'% at '+e.lowAt;
  if(e.recovered) line+=(e.lowAt?', recovered to ':' charged to ')+e.recPct+'% at '+e.recAt;
  line+=' (now '+(nowPct!==undefined?nowPct+'%':'?')+(nowChg?', charging':', not charging')+')';
  return line;
});
flow.set('battNight',{});
node.warn('[low-batt] morning summary: '+eids.length+' phone(s)');
const ALERTS=['notify.mobile_app_np3','notify.mobile_app_pixel_6a'];
const msgTxt='Overnight while notifications were quiet:\n'+lines.join('\n');
return [ALERTS.map(a=>({payload:{action:a,data:{title:'\ud83d\udd0b Overnight battery summary',message:msgTxt,data:{notification_icon:'mdi:battery-clock'}}}}))];

const ev = msg.payload || {};
const mode    = ev.new_state ? ev.new_state.state : '';
const oldMode = (ev.old_state  && ev.old_state.state)  || '';
const guestMode = flow.get('guest_mode') || 'off';
node.warn('[house-alarm] house_mode: ' + oldMode + ' → ' + mode + (guestMode === 'on' ? ' [guest mode]' : ''));
if (mode) flow.set('mode', mode);
if (mode === 'Away') {
    // Guest mode blocks Away arming ONLY (guests moving around would trip it)
    if (guestMode === 'on') { node.warn('[house-alarm] arm away skipped — guest mode active'); return null; }
    if (flow.get('alarm_house') === 'armed_away') { node.warn('[house-alarm] arm away skipped — already armed_away'); return null; }
    return [{}, null, null, {payload:{message:'Nobody is home. Arming the house alarm.'}}];
}
if (mode === 'Sleeping') {
    // Night arming is NOT blocked by guest mode (changed 02-07-2026) — perimeter still armed overnight with guests in
    if (flow.get('alarm_house') === 'armed_night') { node.warn('[house-alarm] arm night skipped — already armed_night'); return null; }
    return [null, {}, null, null];
}
if (mode === 'Home') {
    if (oldMode === 'Away') { flow.set('awaitWelcome', {since: Date.now()}); node.warn('[house-alarm] welcome armed — awaiting front door open'); }
    const needDisarm = flow.get('alarm_house') !== 'disarmed';
    if (!needDisarm) node.warn('[house-alarm] disarm skipped — already disarmed');
    return [null, null, needDisarm ? {} : null, null];
}
return null;

const ents = Array.isArray(msg.payload) ? msg.payload : [];
const hm = ents.find(x => x.entity_id === 'input_select.house_mode');
const gm = ents.find(x => x.entity_id === 'input_boolean.guest_mode');
const mode = hm ? hm.state : '';
const guestMode = gm ? gm.state : 'off';
flow.set('guest_mode', guestMode);
const _ah=ents.find(x=>x.entity_id==='alarm_control_panel.house'); if(_ah){flow.set('alarm_house',_ah.state);global.set('alarm_house',_ah.state);}
const _as=ents.find(x=>x.entity_id==='alarm_control_panel.shed'); if(_as) global.set('alarm_shed',_as.state);
node.warn('[house-alarm] startup: house_mode=' + mode + ' guest_mode=' + guestMode);
if (!mode) return null;
flow.set('mode', mode);
msg.payload = { new_state: { state: mode }, old_state: { state: '' } };
return msg;

const ev = msg.payload || {};
const state = ev.new_state ? ev.new_state.state : '';
flow.set('guest_mode', state);
node.warn('[house-alarm] guest_mode: ' + state);
if (state === 'off') {
    // Guest left — re-evaluate current house_mode
    const mode = flow.get('mode') || '';
    node.warn('[house-alarm] guest_mode off, re-evaluating mode=' + mode);
    msg.payload = { new_state: { state: mode }, old_state: { state: '' } };
    return msg;
}
return null;

// === House Alarm reconcile (safety net for missed house_mode events) ===
// Runs periodically. Compares the CURRENT house_mode to the last one the flow PROCESSED
// (flow.mode). Only if they differ (a change was missed — e.g. Node-RED's HA connection
// blipped at the moment house_mode changed) does it re-apply, by feeding aa-hm-fn a
// synthetic event. Because it keys off flow.mode (not the alarm state), a MANUAL disarm
// — which doesn't change house_mode — is left untouched until house_mode next changes.
const ents = Array.isArray(msg.payload) ? msg.payload : [];
const S = id => { const e = ents.find(x => x.entity_id === id); return e ? e.state : undefined; };

const mode = S('input_select.house_mode');
const guestMode = S('input_boolean.guest_mode') || 'off';
if (!ents.length || !mode) return null;          // no data (e.g. get returned empty) -> do nothing

flow.set('guest_mode', guestMode);               // keep guest state fresh (its watcher could also miss an event)

const lastMode = flow.get('mode') || '';
if (mode === lastMode) return null;              // no missed change -> respect current (incl. manual) state

node.warn('[house-alarm] RECONCILE: missed house_mode change ' + lastMode + ' -> ' + mode + ' — re-applying');
flow.set('mode', mode);
msg.payload = { new_state: { state: mode }, old_state: { state: lastMode } };
return msg;                                       // -> aa-hm-fn (arms/disarms exactly like a real change)

// Night-arm retry (one shot).
// Alarmo refuses arm_night when a door/window is open: the panel STAYS 'disarmed'
// and names the culprits in attribute open_sensors. aa-hm-fn is a state-change
// one-shot on house_mode, so nothing ever tried again -- the house sat unarmed
// all night. This retries ONCE, RETRY_MIN after every blocker is closed again
// (someone got up to shut it; give them time to settle back down).
const RETRY_MIN = 20;
const RETRY_MS  = RETRY_MIN * 60 * 1000;

const ents = Array.isArray(msg.entities) ? msg.entities : [];
if (!ents.length) return null;                       // no snapshot -> can't judge
const S = id => { const e = ents.find(x => x.entity_id === id); return e && e.state; };
const FN = id => { const e = ents.find(x => x.entity_id === id);
                   return (e && e.attributes && e.attributes.friendly_name) || id; };

const hm    = S('input_select.house_mode');
const alarm = S('alarm_control_panel.house');
const now   = Date.now();

// Left Sleeping, or armed by any route -> the whole thing is off. This is also
// where the next night's state gets cleared (incl. na-fn's spoken-once flag).
if (hm !== 'Sleeping' || (alarm && alarm !== 'disarmed')) {
  if (context.get('blockers') || context.get('retryUsed') || flow.get('failSpoken')) {
    node.warn('[night-retry] stand down (house_mode=' + hm + ', alarm=' + alarm + ')');
  }
  context.set('blockers', null);
  context.set('closedSince', null);
  context.set('retryUsed', false);
  flow.set('failSpoken', false);
  return null;
}

// Capture a failed night arm: disarmed + Alarmo naming open sensors, while Sleeping.
const ev = msg.payload || {};
const ns = ev.new_state || {};
if (ev.entity_id === 'alarm_control_panel.house' && ns.state === 'disarmed' &&
    ns.attributes && ns.attributes.open_sensors) {
  if (context.get('retryUsed')) {
    node.warn('[night-retry] arm failed again -- retry already used, standing down');
  } else {
    const b = Object.keys(ns.attributes.open_sensors);
    context.set('blockers', b);
    context.set('closedSince', null);
    node.warn('[night-retry] armed blocked by: ' + b.map(FN).join(', ') + ' -- waiting for all closed');
  }
  return null;
}

const blockers = context.get('blockers');
if (!blockers || !blockers.length) return null;
if (context.get('retryUsed')) return null;

const stillOpen = blockers.filter(id => S(id) !== 'off');
if (stillOpen.length) {                              // re-opened (or never closed) -> clock resets
  if (context.get('closedSince')) node.warn('[night-retry] re-opened: ' + stillOpen.map(FN).join(', ') + ' -- timer reset');
  context.set('closedSince', null);
  return null;
}

let since = context.get('closedSince');
if (!since) {
  context.set('closedSince', now);
  node.warn('[night-retry] all closed -- arming in ' + RETRY_MIN + ' min');
  return null;
}

if (now - since < RETRY_MS) return null;             // still settling

context.set('retryUsed', true);                      // ONE retry, then stop
context.set('closedSince', null);
node.warn('[night-retry] retrying arm_night now');
return {};

const aw = flow.get('awaitWelcome');
const WINDOW = 8 * 60 * 1000;
const opened = msg.payload && msg.payload.new_state && msg.payload.new_state.state === 'on';
if (!opened) return null;
if (!aw || (Date.now() - aw.since) > WINDOW) return null;
flow.set('awaitWelcome', null);
const ents = Array.isArray(msg.entities) ? msg.entities : [];
const S = id => { const e = ents.find(x => x.entity_id === id); return e && e.state; };
const PEOPLE = flow.get('people') || [];
const home = PEOPLE.filter(p => p.name && (S(p.person) === 'home' || S(p.ping) === 'on')).map(p => p.name);
let who = null;
if (home.length === 1) who = home[0];
else if (home.length > 1) who = home.slice(0, -1).join(', ') + ' and ' + home[home.length - 1];
const message = who ? ('Welcome home, ' + who + '. The house has been disarmed.') : 'Welcome home. The house has been disarmed.';
node.warn('[house-alarm] ' + message);
return { payload: { message } };
